"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[11165],{87337:e=>{e.exports=JSON.parse('{"tag":{"label":"growth","permalink":"/dst-api-webdocs/docs/tags/growth","allTagsPath":"/dst-api-webdocs/docs/tags","count":33,"items":[{"id":"game-scripts/prefabs/ancienttree_seed","title":"Ancienttree seed","description":"A deployable item that spawns a randomly generated ancient tree sapling when placed in the world.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ancienttree_seed"},{"id":"game-scripts/prefabs/ancienttrees","title":"Ancienttrees","description":"Manages the lifecycle, growth, and interaction of ancient trees and their saplings, including seed deployment, growth staging, fruit production, and stump conversion upon harvesting.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ancienttrees"},{"id":"game-scripts/prefabs/babybeefalo","title":"Babybeefalo","description":"A growth-stage-based animal prefab that matures through defined life phases, interacts with beefalo herds, and supports combat, foraging, and periodic waste production.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/babybeefalo"},{"id":"game-scripts/prefabs/bananabush","title":"Bananabush","description":"A plantable ground entity that grows through visual stages and yields cave bananas when picked, then regrows over time or resets after being dug up.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bananabush"},{"id":"game-scripts/prefabs/beequeenhive","title":"Beequeenhive","description":"Serves as the initial dormant hive entity that grows over time and eventually spawns a Bee Queen when destroyed; manages hive growth states, honey level visuals, and work-based spawning logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beequeenhive"},{"id":"game-scripts/components/bloomness","title":"Bloomness","description":"Manages the growth stage and bloom progression of a plant entity, including timer-based progression, fertilization effects, and rate calculation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/bloomness"},{"id":"game-scripts/prefabs/books","title":"Books","description":"Defines book prefabs and their associated magical spell effects for the Wickerbottom character, including growth spells, weather manipulation, and entity summoning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/books"},{"id":"game-scripts/components/crop","title":"Crop","description":"Manages growth, maturation, fertilization, and harvesting logic for plant entities in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/crop"},{"id":"game-scripts/prefabs/deciduoustrees","title":"Deciduoustrees","description":"Manages deciduous tree prefabs, including growth stages, seasonal leaf changes, monster transformation, burning behavior, and loot generation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/deciduoustrees"},{"id":"game-scripts/prefabs/evergreens","title":"Evergreens","description":"Manages evergreen tree prefabs with multi-stage growth, loot dropping, burning, hauntable behavior, and regeneration mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/evergreens"},{"id":"game-scripts/prefabs/farm_plants","title":"Farm Plants","description":"Manages farm plant lifecycle, stress tracking, growth stages, and loot generation for agricultural gameplay.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/farm_plants"},{"id":"game-scripts/components/growable","title":"Growable","description":"Manages staged growth progress for entities, supporting timed, paused, and sleep-aware growth with stage transitions and save/load persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/components/growable"},{"id":"game-scripts/components/grower","title":"Grower","description":"Manages crop growth and fertility for plot-like entities, tracking soil cycles and planted crops.","permalink":"/dst-api-webdocs/docs/game-scripts/components/grower"},{"id":"game-scripts/components/harvestable","title":"Harvestable","description":"Manages plant-like entities that grow over time and can be harvested to yield items, handling growth progress, pausing, and item dropping.","permalink":"/dst-api-webdocs/docs/game-scripts/components/harvestable"},{"id":"game-scripts/prefabs/livingtree_root_planted","title":"Livingtree root planted","description":"A planted living tree seed that grows over two stages into a harvestable sapling, which then transforms into a livingtree_halloween upon growth completion.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/livingtree_root_planted"},{"id":"game-scripts/prefabs/marbleshrub","title":"Marbleshrub","description":"Manages the growth, mining, and loot generation of marble shrubs, which are mutable ground structures that progress through growth stages and yield marble resources when mined.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/marbleshrub"},{"id":"game-scripts/prefabs/moontree","title":"Moontree","description":"Manages the lifecycle, growth stages, burning, and harvesting of moon trees in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moontree"},{"id":"game-scripts/prefabs/mushtree","title":"Mushtree","description":"Manages lifecycle, growth, seasonal changes, acid rain effects, and loot generation for mushtree entities in the Cave biome.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushtree"},{"id":"game-scripts/prefabs/oceantree","title":"Oceantree","description":"Manages the lifecycle, growth, and interaction logic for ocean trees, including chopping, burning, converting to stumps, and transforming into ocean pillars when enriched.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceantree"},{"id":"game-scripts/prefabs/oceantreenut","title":"Oceantreenut","description":"A salvageable ocean object that periodically attempts to grow into an Oceantree when submerged and conditions are met.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceantreenut"},{"id":"game-scripts/components/pickable","title":"Pickable","description":"Manages the harvestable lifecycle of entities that regrow over time, including regen timers, fertility states, and loot dropping behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/pickable"},{"id":"game-scripts/components/plantable","title":"Plantable","description":"Initializes core growth parameters for plants, such as grow time and final product.","permalink":"/dst-api-webdocs/docs/game-scripts/components/plantable"},{"id":"game-scripts/prefabs/planted_tree","title":"Planted Tree","description":"Provides shared logic and factory functions for sapling prefabs that grow into trees after a timed period, with support for digging to harvest early.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/planted_tree"},{"id":"game-scripts/prefabs/rock_avocado_fruit","title":"Rock Avocado Fruit","description":"Manages the lifecycle and interactivity of rock avocado plant variants, including harvesting, cooking, planting, and growth.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rock_avocado_fruit"},{"id":"game-scripts/prefabs/rocky","title":"Rocky","description":"Manages Rocky\'s behavior as a controllable NPC character, including growth mechanics, follower loyalty, combat targeting, and interaction with players via trading.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rocky"},{"id":"game-scripts/components/simplemagicgrower","title":"Simplemagicgrower","description":"Triggers incremental growth stages on an entity using repeated automatic calls to Growable:DoGrowth until a target stage is reached.","permalink":"/dst-api-webdocs/docs/game-scripts/components/simplemagicgrower"},{"id":"game-scripts/prefabs/smallbird","title":"Smallbird","description":"Manages the lifecycle, behavior, and growth progression of small birds (including their teenage and adult tallbird forms) as companions with combat, eating, sleeping, and follower mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/smallbird"},{"id":"game-scripts/components/treegrowthsolution","title":"Treegrowthsolution","description":"Applies growth progression to a target tree entity, consuming the solution item after use.","permalink":"/dst-api-webdocs/docs/game-scripts/components/treegrowthsolution"},{"id":"game-scripts/prefabs/waterplant_baby","title":"Waterplant Baby","description":"A juvenile waterplant entity that grows barnacles over time and transforms into a fully grown waterplant under specific conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/waterplant_baby"},{"id":"game-scripts/prefabs/weed_defs","title":"Weed Defs","description":"Defines configuration and behavior templates for weed plants, including growth stages, spread mechanics, and custom actions for forgetmelots, tillweed, firenettle, and ivy.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/weed_defs"},{"id":"game-scripts/prefabs/weed_plants","title":"Weed Plants","description":"A reusable prefab factory that creates customizable farmable weeds with growth stages, soil interaction, and magical growth mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/weed_plants"},{"id":"game-scripts/prefabs/winter_tree","title":"Winter Tree","description":"Manages growth stages, decoration, lighting, and gift-giving behavior for seasonal winter trees during the Winters Feast event.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winter_tree"},{"id":"game-scripts/prefabs/winter_treestand","title":"Winter Treestand","description":"A structure that can be planted with a winter tree seed to grow into a full winter tree and yields wood when harvested before full growth.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winter_treestand"}],"unlisted":false}}')}}]);